    // Since k is at most 5, we only need to compute depths up to 5
    // We'll use BFS to find the popcount-depth for each number

    // Function to calculate the popcount of a number
    function popcount(x: number): number {
        let count = 0;
        while (x) {
            x &= x - 1; // Clear the least significant bit
            count++;
        }
        return count;
    }

    // Function to calculate the popcount-depth of a number
    function getDepth(x: number): number {
        let depth = 0;
        while (x !== 1) {
            x = popcount(x);
            depth++;
        }
        return depth;
    }

    // Use BFS to find all numbers with popcount-depth exactly k
    // We'll use a queue to process numbers level by level
    // We'll also use a visited set to avoid reprocessing numbers
    const queue: number[] = [];
    const visited: Set<number> = new Set();
    const result: number[] = [];

    // Start with all numbers that have popcount 1 (depth 1)
    for (let i = 1; i <= n; i++) {
        if (popcount(i) === 1) {
            queue.push(i);
            visited.add(i);
        }
    }

    // BFS to find numbers with depth k
    while (queue.length > 0) {
        const current = queue.shift()!;
        const depth = getDepth(current);
        if (depth === k) {
            result.push(current);
        }

        // Generate next numbers by taking the popcount of current
        const next = popcount(current);
        if (next <= n && !visited.has(next)) {
            visited.add(next);
            queue.push(next);
        }
    }

    return result.length;
}

